// Solution
class Solution {
 public:
  vector<int> getInorderTraversal(vector<int>& preorder) {
   stack<int> st;
   st.push(preorder[0]);
   for (int i = 1; i < preorder.size(); i++) {
    if (preorder[i] < preorder[0])
     st.push(preorder[i]);
    else {
     while (!st.empty() && preorder[i] > st.top())
      st.pop();
     st.push(preorder[i]);
    }
   }
   vector<int> inorder;
   while (!st.empty()) {
    inorder.push_back(st.top());
    st.pop();
   }
   return inorder;
  }
};

