  stack = [preorder[0]]
  inorder = []
  for num in preorder[1:]:
   if num < preorder[0]:
    stack.append(num)
   else:
    while stack and num > stack[-1]:
     inorder.append(stack.pop())
    stack.append(num)
  while stack:
   inorder.append(stack.pop())
  return inorder

